head.b:skin:
/* Minimalist CSS for AI Agent Interface */
body { font-family: 'Inter', sans-serif; background: #f4f7f6; margin: 0; padding: 0; }
#ai-agent-container { max-width: 800px; margin: 50px auto; background: #fff; border-radius: 12px; box-shadow: 0 10px 30px rgba(0,0,0,0.1); overflow: hidden; display: flex; flex-direction: column; height: 80vh; }

/* Header */
.agent-header { background: #1a73e8; color: white; padding: 20px; display: flex; justify-content: space-between; align-items: center; }
.status-pill { background: #34a853; font-size: 12px; padding: 4px 12px; border-radius: 20px; }

/* Chat Window */
#chat-window { flex: 1; padding: 20px; overflow-y: auto; display: flex; flex-direction: column; gap: 15px; }
.msg { max-width: 80%; padding: 12px 16px; border-radius: 18px; line-height: 1.5; }
.msg.user { align-self: flex-end; background: #e3f2fd; color: #1565c0; }
.msg.bot { align-self: flex-start; background: #f1f3f4; color: #3c4043; }
.msg.system { align-self: center; font-size: 11px; color: #70757a; text-transform: uppercase; }

/* Input Area */
.input-area { border-top: 1px solid #eee; padding: 20px; display: flex; gap: 10px; }
input#user-input { flex: 1; border: 1px solid #ddd; padding: 12px; border-radius: 8px; outline: none; }
button#send-btn { background: #1a73e8; color: white; border: none; padding: 10px 20px; border-radius: 8px; cursor: pointer; transition: 0.3s; }
button#send-btn:hover { background: #1557b0; }

/* Tool Indicators */
.tool-tag { font-size: 10px; font-weight: bold; margin-top: 5px; display: block; color: #1a73e8; }

body.script:
 // CONFIGURATION: Replace with your actual proxy/middleware URL
const PROXY_ENDPOINT = "https://zap-ai-1zcd.vercel.app/api/agent";

 async function sendMessage() {
     const inputField = document.getElementById('user-input');
     const chatWindow = document.getElementById('chat-window');
     const query = inputField.value.trim();

     if (!query) return;

     // Add User Message
     appendMessage(query, 'user');
     inputField.value = '';

     // Add Thinking Placeholder
     const thinkingId = 'think-' + Date.now();
     appendMessage("Interfacing with Zapier MCP...", 'bot', thinkingId);

     try {
         const response = await fetch(PROXY_ENDPOINT, {
             method: 'POST',
             headers: { 'Content-Type': 'application/json' },
             body: JSON.stringify({ 
                 prompt: query,
                 tools: ["github", "gmail", "sheets", "docs", "rss"] 
             })
         });

         const data = await response.json();

         // Remove thinking message and add actual response
         document.getElementById(thinkingId).remove();
         appendMessage(data.output, 'bot', null, data.toolUsed);

     } catch (error) {
         document.getElementById(thinkingId).innerText = "Error: Could not connect to the MCP server.";
     }
 }

 function appendMessage(text, type, id = null, tool = null) {
     const chatWindow = document.getElementById('chat-window');
     const msgDiv = document.createElement('div');
     msgDiv.className = `msg ${type}`;
     if (id) msgDiv.id = id;

     let content = text;
     if (tool) {
         content += `Used Tool: ${tool}`;
     }

     msgDiv.innerHTML = content;
     chatWindow.appendChild(msgDiv);
     chatWindow.scrollTop = chatWindow.scrollHeight;
 }

 // Allow 'Enter' key to send
 document.getElementById('user-input').addEventListener('keypress', function (e) {
     if (e.key === 'Enter') sendMessage();
 });
